import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import { authService, studentService } from '../services/api';

const DEPTS = ['Computer Science & Engineering','Electronics & Communication','Mechanical Engineering','Civil Engineering','Electrical Engineering','Information Technology','Master of Computer Applications'];
const BATCH_YEARS = Array.from({length:8}, (_, i) => 2023+i);

export default function LoginPage() {
  const [tab, setTab] = useState('login');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();
  const [lf, setLf] = useState({ email: '', password: '' });
  const [rf, setRf] = useState({ firstName:'',lastName:'',email:'',password:'',confirmPassword:'',rollNumber:'',department:'',batchYear:'',phone:'',gender:'',dateOfBirth:'',cgpa:'',skills:'',linkedinUrl:'',coverNote:'',resume:null });

  const handleLogin = async e => {
    e.preventDefault(); setLoading(true);
    try {
      const { data } = await authService.login(lf);

      // Login with basic data immediately
      login(data);
      toast.success(`Welcome back, ${data.firstName}!`);
      navigate(data.role === 'ADMIN' ? '/admin' : '/student');

      // For students, fetch full profile in background to enrich user data
      if (data.role === 'STUDENT') {
        studentService.getProfile()
          .then(({ data: profileData }) => {
            // Update context with full profile data
            login({ ...data, ...profileData });
          })
          .catch(err => console.warn('Could not fetch student profile:', err));
      }
    } catch (err) { toast.error(err.response?.data?.message || 'Invalid credentials.'); }
    finally { setLoading(false); }
  };

  const handleRegister = async e => {
    e.preventDefault();
    // Validation checks
    if (!rf.firstName.trim() || !rf.lastName.trim()) return toast.error('First and last name are required.');
    if (!/^[a-zA-Z\s]+$/.test(rf.firstName) || !/^[a-zA-Z\s]+$/.test(rf.lastName)) return toast.error('First and last name must contain characters only.');
    if (rf.password.length < 8) return toast.error('Password must be at least 8 characters.');
    if (rf.password !== rf.confirmPassword) return toast.error('Passwords do not match.');
    if (!rf.rollNumber.trim()) return toast.error('Roll number is required.');
    if (!/^[a-zA-Z0-9]+$/.test(rf.rollNumber)) return toast.error('Roll number must be alphanumeric.');
    if (!rf.batchYear.trim()) return toast.error('Batch year is required.');
    if (!rf.dateOfBirth.trim()) return toast.error('Date of birth is required.');
    const dobYear = parseInt(new Date(rf.dateOfBirth).getFullYear());
    if (dobYear >= 2010) return toast.error('Date of birth must be before 2010.');
    if (!rf.skills.trim()) return toast.error('Skills are required.');
    const skillsArr = rf.skills.split(',').map(s => s.trim()).filter(s => s.length > 0);
    if (skillsArr.length === 0) return toast.error('Please enter at least one skill (comma-separated).');
    if (!rf.email.endsWith('@students.git.edu')) return toast.error('Only @students.git.edu emails allowed.');
    if (!rf.department) return toast.error('Department is required.');

    setLoading(true);
    try {
      const formData = new FormData();
      const registerData = {
        firstName:rf.firstName, lastName:rf.lastName, email:rf.email, password:rf.password,
        rollNumber:rf.rollNumber, department:rf.department, batchYear:rf.batchYear,
        phone:rf.phone, gender:rf.gender, dateOfBirth:rf.dateOfBirth,
        cgpa:rf.cgpa, skills:rf.skills, linkedinUrl:rf.linkedinUrl, coverNote:rf.coverNote
      };
      formData.append('registerData', new Blob([JSON.stringify(registerData)], { type: 'application/json' }));
      if (rf.resume) formData.append('resume', rf.resume);

      const { data } = await authService.registerWithFile(formData);
      toast.success(data.message); navigate('/pending');
    } catch (err) { toast.error(err.response?.data?.message || 'Registration failed.'); }
    finally { setLoading(false); }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">
          <div className="login-logo-icon">
            <svg width="26" height="26" viewBox="0 0 24 24" fill="#c9a84c"><path d="M12 3L1 9l11 6 9-4.91V17h2V9L12 3zm-8.99 9.18L12 17l8.99-4.82.01 4.09-9 4.91-9-4.91.01-4.09z"/></svg>
          </div>
          <div>
            <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:'var(--navy)',marginBottom:2}}>GIT Placement Portal</h2>
            <p style={{fontSize:11,color:'var(--gray-400)',letterSpacing:'0.5px'}}>CAMPUS RECRUITMENT SYSTEM</p>
          </div>
        </div>
        <div className="login-tabs">
          <button className={`login-tab${tab==='login'?' active':''}`} onClick={()=>setTab('login')}>Sign In</button>
          <button className={`login-tab${tab==='register'?' active':''}`} onClick={()=>setTab('register')}>Register</button>
        </div>
        <div className="domain-badge"><div className="domain-dot"/>{tab==='login'?'Admin or @students.git.edu':'@students.git.edu only'}</div>

        {tab==='login' && (
          <form onSubmit={handleLogin}>
            <div className="form-group"><label>Email</label><input type="email" placeholder="yourname@students.git.edu" value={lf.email} onChange={e=>setLf(p=>({...p,email:e.target.value}))} required /></div>
            <div className="form-group"><label>Password</label><input type="password" placeholder="Enter your password" value={lf.password} onChange={e=>setLf(p=>({...p,password:e.target.value}))} required /></div>
            <button type="submit" className="btn btn-primary btn-full btn-lg" disabled={loading}>{loading?'Signing in…':'Sign In to Portal'}</button>
            <p style={{textAlign:'center',marginTop:16,fontSize:13,color:'var(--gray-400)'}}>No account? <span onClick={()=>setTab('register')} style={{color:'var(--navy)',fontWeight:600,cursor:'pointer'}}>Register here</span></p>
          </form>
        )}

        {tab==='register' && (
          <form onSubmit={handleRegister}>
            <div className="form-row">
              <div className="form-group"><label>First Name *</label><input type="text" placeholder="Characters only" required value={rf.firstName} onChange={e=>setRf(p=>({...p,firstName:e.target.value}))}/></div>
              <div className="form-group"><label>Last Name *</label><input type="text" placeholder="Characters only" required value={rf.lastName} onChange={e=>setRf(p=>({...p,lastName:e.target.value}))}/></div>
            </div>
            <div className="form-group"><label>College Email *</label><input type="email" placeholder="yourname@students.git.edu" required value={rf.email} onChange={e=>setRf(p=>({...p,email:e.target.value}))}/></div>
            <div className="form-row">
              <div className="form-group"><label>Password *</label><input type="password" placeholder="Min. 8 chars" required value={rf.password} onChange={e=>setRf(p=>({...p,password:e.target.value}))}/></div>
              <div className="form-group"><label>Confirm *</label><input type="password" placeholder="Repeat" required value={rf.confirmPassword} onChange={e=>setRf(p=>({...p,confirmPassword:e.target.value}))}/></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Roll Number *</label><input type="text" placeholder="GIT2024CS001 (alphanumeric)" required value={rf.rollNumber} onChange={e=>setRf(p=>({...p,rollNumber:e.target.value}))}/></div>
              <div className="form-group"><label>Batch Year *</label>
                <select required value={rf.batchYear} onChange={e=>setRf(p=>({...p,batchYear:e.target.value}))}>
                  <option value="">Select batch year</option>
                  {BATCH_YEARS.map(y=><option key={y}>{y}</option>)}
                </select>
              </div>
            </div>
            <div className="form-group"><label>Department *</label>
              <select required value={rf.department} onChange={e=>setRf(p=>({...p,department:e.target.value}))}>
                <option value="">Select department</option>
                {DEPTS.map(d=><option key={d}>{d}</option>)}
              </select>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Phone</label><input type="text" placeholder="+91 XXXXX XXXXX" value={rf.phone} onChange={e=>setRf(p=>({...p,phone:e.target.value}))}/></div>
              <div className="form-group"><label>Gender</label>
                <select value={rf.gender} onChange={e=>setRf(p=>({...p,gender:e.target.value}))}>
                  <option value="">Select</option>
                  <option>Male</option><option>Female</option><option>Other</option>
                </select>
              </div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Date of Birth *</label><input type="date" required value={rf.dateOfBirth} onChange={e=>setRf(p=>({...p,dateOfBirth:e.target.value}))}/></div>
              <div className="form-group"><label>CGPA</label><input type="text" placeholder="e.g. 8.5" value={rf.cgpa} onChange={e=>setRf(p=>({...p,cgpa:e.target.value}))}/></div>
            </div>
            <div className="form-group"><label>Skills * (comma separated)</label><input type="text" placeholder="Java, React, Python, SQL…" required value={rf.skills} onChange={e=>setRf(p=>({...p,skills:e.target.value}))}/></div>
            <div className="form-group"><label>LinkedIn URL</label><input type="text" placeholder="https://linkedin.com/in/yourname" value={rf.linkedinUrl} onChange={e=>setRf(p=>({...p,linkedinUrl:e.target.value}))}/></div>
            <div className="form-group"><label>Cover Note (Optional)</label><textarea rows={3} placeholder="Describe your career interests…" value={rf.coverNote} onChange={e=>setRf(p=>({...p,coverNote:e.target.value}))}/></div>
            <div className="form-group"><label>Resume (Optional - PDF/DOCX, max 5MB)</label><input type="file" accept=".pdf,.docx" onChange={e=>setRf(p=>({...p,resume:e.target.files?.[0]||null}))}/></div>
            <button type="submit" className="btn btn-gold btn-full btn-lg" disabled={loading}>{loading?'Submitting…':'Submit for Approval'}</button>
            <p style={{textAlign:'center',marginTop:16,fontSize:13,color:'var(--gray-400)'}}>Have account? <span onClick={()=>setTab('login')} style={{color:'var(--navy)',fontWeight:600,cursor:'pointer'}}>Sign in</span></p>
          </form>
        )}
      </div>
    </div>
  );
}
